SourceCode.Declaration:
/// <summary>
/// Class to activate the new tracking dimension "application" for the ETGSPAIN model.
/// </summary>
final class ETGSPAINInventTrackingDimension_Application extends InventTrackingDimension
{
}

Method.Source:
/// <summary>
/// Assigns the index.
/// </summary>
/// <param name="_tableId">Table ID.</param>
/// <returns>Returns the index number.</returns>
public IndexId indexHintForTable(TableId _tableId)
{
    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        switch (_tableId)
        {
            case tableNum(InventDim):
                return IndexNum(InventDim, InventDimension1Idx);
        }
    }
    return 0;
}

/// <summary>
/// Gets the instance of the new dimension.
/// </summary>
/// <returns>Returns the instance.</returns>
public static ETGSPAINInventTrackingDimension_Application getInstance()
{

    ETGSPAINInventTrackingDimension_Application instance;

    if (CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        instance = InventDimension::singletonFromInventDimFieldId(
        fieldNum(InventDim, InventDimension1)
    ) as ETGSPAINInventTrackingDimension_Application;
    }

    return instance;
}

/// <summary>
/// Specifies whether the dimension affects price calculation.
/// </summary>
/// <returns>Always returns true.</returns>
public boolean isAffectingPrice()
{
    boolean isAffecting = false;

    if (CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        isAffecting = true;
    }

    return isAffecting;
}

/// <summary>
/// Checks the value of the item's tracking dimension.
/// </summary>
/// <param name="_inventTable">The inventory table.</param>
/// <param name="_value">The value to validate.</param>
/// <returns>True if valid; otherwise, false.</returns>
public boolean checkExistsValueForItem(InventTable _inventTable, anytype _value)
{
    boolean ret;
    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        ret = ETGSPAINInventApplicationTable::exist(_value);
    }
    return ret;
}
